mapper.update:
UPDATE customers
SET status = #{status},
    updated_at = #{updatedAt}
WHERE id = #{customerId}

UPDATE customers
SET tier = #{tier},
    updated_at = #{updatedAt}
WHERE id = #{customerId}

mapper.select:
SELECT COALESCE(SUM(order_amount), 0)
FROM customer_orders
WHERE customer_id = #{customerId}
  AND order_date >= #{startDate}
  AND status = 'COMPLETED'
